mapper.sql:
SELECT
ID,
RULE_NAME,
EMPTY_WEIGHT,
HEAVY_WEIGHT,
IS_DEFAULT,
TRANSPORT_TYPE,
CARGO_CODE,
CARGO_NAME
FROM
M_WEIGHT_RULES


        and ID = #{id}


        and RULE_NAME = #{ruleName}


        and EMPTY_WEIGHT = #{emptyWeight}


        and HEAVY_WEIGHT = #{heavyWeight}


        and IS_DEFAULT = #{isDefault}


        and TRANSPORT_TYPE = #{transportType}


        and CARGO_CODE = #{cargoCode}


        and CARGO_NAME = #{cargoName}
